export type ElementCategory = 'maps' | 'coat_of_arms' | 'animals' | 'plants' | 'symbols';

export interface AutoPlace {
  /** Horizontal center as a fraction of canvas width (0–1) */
  xCenter: number;
  /** Vertical center as a fraction of canvas height (0–1) */
  yCenter: number;
  /** Element size as a fraction of canvas height */
  sizeFraction: number;
}

export interface FlagElement {
  id: string;
  name: string;
  /** Country or flag this element comes from */
  flagOf: string;
  category: ElementCategory;
  /** Suggested hex color as used on the real flag */
  defaultColor: string;
  /** SVG shape elements for viewBox="0 0 100 100". Uses currentColor for fill/stroke. */
  svgContent: string;
  /**
   * When present, the element is stamped automatically at this position/size
   * instead of entering interactive placement mode.
   */
  autoPlace?: AutoPlace;
}

